import{_ as a,c as t,o as r,a2 as o}from"./chunks/framework.CIiVzG-O.js";const m=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1782362536000}'),p={name:"guide/faq.md"};function n(s,e,i,d,l,u){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><p>Q: What is PetReminder?</p><p>A: PetReminder is a macOS desktop app that shows cute pets on your screen when reminders are due. It helps you stay on top of important tasks with adorable animal companions.</p><p>Q: Which macOS versions are supported?</p><p>A: PetReminder runs on macOS Monterey (12) and later, optimized for Apple Silicon (M-series).</p><p>Q: How do I download and install PetReminder?</p><p>A: Download from the <a href="https://apps.apple.com/app/id6776577400" target="_blank" rel="noreferrer">Mac App Store</a>.</p><p>Q: Is PetReminder free?</p><p>A: The base app is free to download. Some premium pets are available via in-app purchase.</p><p>Q: What pets are available?</p><p>A: Currently includes free default pet plus premium breeds: <strong>Ragdoll Cat</strong>, <strong>British Shorthair Cat</strong>, <strong>Shiba Inu</strong>, <strong>Corgi</strong>, and <strong>Husky</strong>. More coming soon!</p><p>Q: How do I purchase a premium pet?</p><p>A: Open PetReminder → <strong>Pets</strong> tab, browse available pets, and tap &quot;Purchase&quot; to unlock via in-app purchase.</p><p>Q: Does PetReminder work offline?</p><p>A: Yes. Reminders and pet animations work fully offline. Only pet downloads from IAP require an internet connection.</p><p>Q: Does PetReminder upload my data?</p><p>A: No. PetReminder is offline-first. All your reminders and settings are stored locally. No data is uploaded to external servers.</p><p>Q: How do I update the app?</p><p>A: Update through the Mac App Store (recommended) or download the latest release from GitHub.</p><p>Q: How do I report bugs or request features?</p><p>A: Open an issue in the <a href="https://github.com/petreminder/reminder" target="_blank" rel="noreferrer">project repository</a> and include your macOS version, PetReminder version, reproduction steps, and logs if available.</p><p>Q: Where are logs and data stored?</p><p>A: For sandboxed (App Store) builds:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Containers/com.w3cub.reminder/Data/Library/Application Support/com.w3cub.reminder/</span></span></code></pre></div><p>Development builds may log to the console or <code>src-tauri</code> directory.</p><p>If you need more answers, please open an issue in the repository or consult the full documentation.</p>',26)])])}const h=a(p,[["render",n]]);export{m as __pageData,h as default};
